var size = context.TileSize;
var seed = GetInt(parameters, "seed", context.Seed);
var selectionParam = GetInt(parameters, "selection", -1);

int choice;
if (selectionParam >= 0 && selectionParam < inputs.Length)
{
    // Explicit selection: use the user-specified index
    choice = selectionParam;
}
else
{
    // Auto/random mode (-1 or out of range): pick a non-null input using seed
    var validInputs = new System.Collections.Generic.List<int>();
    for (var i = 0; i < inputs.Length; i++)
        if (inputs[i] != null) validInputs.Add(i);

    if (validInputs.Count == 0)
        return new PixelBuffer(size, size);

    var pick = (int)(HashToUnit(0, 0, seed) * validInputs.Count) % validInputs.Count;
    choice = validInputs[pick];
}

// Try the selected input first
if (choice >= 0 && choice < inputs.Length && inputs[choice] != null)
    return inputs[choice]!.Clone();

// Fallback to the first non-null input
for (var i = 0; i < inputs.Length; i++)
{
    if (inputs[i] != null)
        return inputs[i]!.Clone();
}

// No valid input found
return new PixelBuffer(size, size);
}
